request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?type ?comment WHERE {
  ?task bbo:name ?taskName .
  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("manuf")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("manufact")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("manufat"))
  )
  OPTIONAL { ?task a ?type . }
  OPTIONAL { ?task rdfs:comment ?comment . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?model ?modelName ?originalId ?participantName WHERE {
  ?participant a bboExt:Participant ;
               bbo:name ?participantName ;
               tai:belongsTo ?choreo .

  FILTER(
    CONTAINS(LCASE(STR(?participantName)), LCASE("manufat")) ||
    CONTAINS(LCASE(STR(?participantName)), LCASE("manufact")) ||
    CONTAINS(LCASE(STR(?participantName)), LCASE("manufacturer")) ||
    CONTAINS(LCASE(STR(?participantName)), LCASE("manuf"))
  )

  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bboExt:initiatingParticipantRef ?partRef ;
        tai:belongsTo ?choreo .

  FILTER(STRENDS(STR(?participant), ?partRef))

  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
}
LIMIT 25
